sql:
SELECT sector, MAX(market_cap) AS max_market_cap
FROM stocks
GROUP BY sector;

SELECT date, close_price
FROM historical_data
ORDER BY date ASC;

SELECT AVG(close_price) AS average_close_price
FROM historical_data
WHERE stock_id = (SELECT stock_id FROM stocks WHERE stock_symbol = 'AAPL');

external_knowledge:
- "more popular companies" relates to those with higher access counts in the past month;
- "recent market performance has been strong" implies a high average adjusted closing price;
- "past month" corresponds to the last 30 days;
- "sorted by market strength and popularity" translates to being sorted by average adjusted closing price (descending) and access count (descending).
